import React, { useEffect, useState } from "react";
import { useParams, Link } from "react-router-dom";
import { useApp } from "../contexts/AppContext";
import { ArrowLeft } from "lucide-react";
import WhatsAppIcon from "../components/WhatsAppIcon";
import { buildWaUrl, productMessage } from "../lib/whatsapp";

const ProductDetail = () => {
  const { id } = useParams();
  const { formatPrice, whatsappNumber } = useApp();
  const [product, setProduct] = useState(null);
  const [imgIdx, setImgIdx] = useState(0);

  useEffect(() => {
    const loadProduct = async () => {
      try {
        const response = await fetch("http://localhost:5000/api/products");
        if (!response.ok) throw new Error("Failed to load products");
        const products = await response.json();
        console.log("Available products:", products.map(p => p.id));
        console.log("Looking for id:", id);
        // Procurar produto pelo id (pode ser string ou number)
        const found = products.find(p => String(p.id) === String(id));
        console.log("Found product:", found);
        setProduct(found || null);
      } catch (err) {
        console.error("ProductDetail load error", err);
        setProduct(null);
      }
    };

    if (id) {
      loadProduct();
    }
  }, [id]);

  if (!product) return <div className="px-6 py-20 text-sm text-[#A68A72]">…</div>;

  const name = product.name_en;
  const desc = product.description_en;
  const notes = product.scent_notes_en;
  const images = product.images?.length ? product.images : [""];
  const waHref = buildWaUrl(whatsappNumber, productMessage(product));

  return (
    <main data-testid="product-detail-page" className="px-6 md:px-12 lg:px-20 pt-10 pb-24">
      <Link to="/shop" className="inline-flex items-center gap-2 text-xs uppercase tracking-luxe text-[#8B5E3C] hover:text-[#5C3A21] mb-10">
        <ArrowLeft className="w-4 h-4" strokeWidth={1.5} /> Back to shop
      </Link>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 lg:gap-20">
        <div className="lg:col-span-6">
          <div className="product-img-wrap aspect-[4/5] bg-[#EDE4D8] mb-4 max-w-[520px]">
            <img src={images[imgIdx]} alt={name} className="w-full h-full object-cover" />
          </div>
          {images.length > 1 && (
            <div className="flex gap-3">
              {images.map((src, i) => (
                <button
                  key={i}
                  onClick={() => setImgIdx(i)}
                  className={`w-20 h-24 bg-[#EDE4D8] overflow-hidden border-2 ${
                    i === imgIdx ? "border-[#8B5E3C]" : "border-transparent"
                  }`}
                >
                  <img src={src} alt="" className="w-full h-full object-cover" />
                </button>
              ))}
            </div>
          )}
        </div>

        <div className="lg:col-span-6 lg:pt-6">
          <h1 className="font-serif-display text-4xl sm:text-5xl">{name}</h1>
          <p className="mt-4 text-xl text-[#8B5E3C]">
            {formatPrice(undefined, product.price_gbp)}
          </p>

          {desc && (
            <div className="mt-10">
              <div className="text-xs tracking-luxe uppercase text-[#8B5E3C] mb-3">Description</div>
              <p className="text-[#3B2618]/80 leading-relaxed">{desc}</p>
            </div>
          )}

          {notes && (
            <div className="mt-8">
              <div className="text-xs tracking-luxe uppercase text-[#8B5E3C] mb-3">Scent Notes</div>
              <p className="text-[#3B2618]/80 leading-relaxed text-sm">{notes}</p>
            </div>
          )}

          <a
            data-testid="detail-whatsapp-btn"
            href={waHref}
            target="_blank"
            rel="noopener noreferrer"
            className="mt-10 inline-flex items-center justify-center gap-3 w-full bg-[#25D366] text-white py-4 px-8 text-xs tracking-luxe uppercase hover:bg-[#1ea854] transition-colors"
          >
            <WhatsAppIcon className="w-5 h-5" />
            Order via WhatsApp
          </a>

          <p className="mt-3 text-xs text-[#A68A72] text-center">
            Personal service · Reply in minutes
          </p>
        </div>
      </div>
    </main>
  );
};

export default ProductDetail;
