import React, { createContext, useContext, useEffect, useState, useCallback } from "react";
import { tt } from "../i18n/translations";

const AppCtx = createContext(null);

export const AppProvider = ({ children }) => {
  const [token, setToken] = useState(() => localStorage.getItem("ef_token"));
  const [settings, setSettings] = useState(null);

  useEffect(() => {
    const loadSettings = async () => {
      try {
        const response = await fetch("http://localhost:5000/api/settings");
        if (!response.ok) throw new Error("Failed to load settings");
        const data = await response.json();
        setSettings(data || {});
      } catch (e) {
        console.error("Failed to load settings", e);
        setSettings({});
      }
    };

    loadSettings();
  }, []);

  const t = useCallback((path) => tt("en", path), []);

  const formatPrice = useCallback((priceEur, priceGbp) => {
    return `£${(priceGbp ?? 0).toFixed(2)}`;
  }, []);

  const login = useCallback(async (email, password) => {
    const response = await fetch(`${process.env.REACT_APP_BACKEND_URL || "http://localhost:5000"}/api/auth/login`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ email, password }),
    });

    if (!response.ok) {
      throw new Error("Invalid credentials");
    }

    const data = await response.json();
    localStorage.setItem("ef_token", data.access_token);
    setToken(data.access_token);
    return data;
  }, []);

  const logout = useCallback(async () => {
    localStorage.removeItem("ef_token");
    setToken(null);
  }, []);

  const whatsappNumber = settings?.whatsapp_number || "351932952049";

  return (
    <AppCtx.Provider
      value={{
        t, formatPrice,
        token, login, logout, settings, setSettings, whatsappNumber,
      }}
    >
      {children}
    </AppCtx.Provider>
  );
};

export const useApp = () => {
  const ctx = useContext(AppCtx);
  if (!ctx) throw new Error("useApp must be inside AppProvider");
  return ctx;
};
