import React, { useState, useEffect, useLayoutEffect, useCallback, useMemo, useRef } from "react";
import { Link, useLocation } from "react-router-dom";
import { Menu, X, Search } from "lucide-react";
import { useApp } from "../contexts/AppContext";
import WhatsAppIcon from "./WhatsAppIcon";
import { buildWaUrl, generalMessage } from "../lib/whatsapp";

const Header = () => {
  const { t, whatsappNumber } = useApp();
  const [menuOpen, setMenuOpen] = useState(false);
  const [activeHash, setActiveHash] = useState("");
  const [indicatorStyle, setIndicatorStyle] = useState({ left: 0, width: 0, opacity: 0 });
  const loc = useLocation();
  const navRef = useRef(null);
  const navRefs = useRef({});

  const activeKey = useMemo(() => {
    if (loc.pathname === "/") {
      if (activeHash === "#about") return "about";
      if (activeHash === "#fragrances") return "fragrances";
      if (activeHash === "#contact") return "contact";
      return "home";
    }
    if (loc.pathname === "/shop") return "shop";
    return null;
  }, [loc.pathname, activeHash]);

  const updateIndicator = useCallback(() => {
    if (!navRef.current || !activeKey) {
      setIndicatorStyle((prev) => ({ ...prev, opacity: 0 }));
      return;
    }

    const activeEl = navRefs.current[`nav-${activeKey}`];
    if (!activeEl) {
      setIndicatorStyle((prev) => ({ ...prev, opacity: 0 }));
      return;
    }

    const navRect = navRef.current.getBoundingClientRect();
    const itemRect = activeEl.getBoundingClientRect();
    setIndicatorStyle({
      left: itemRect.left - navRect.left,
      width: itemRect.width,
      opacity: 1,
    });
  }, [activeKey]);

  useLayoutEffect(() => {
    updateIndicator();
  }, [updateIndicator]);

  useEffect(() => {
    window.addEventListener("resize", updateIndicator);
    return () => window.removeEventListener("resize", updateIndicator);
  }, [updateIndicator]);

  useEffect(() => {
    if (loc.pathname !== "/") {
      setActiveHash("");
      return;
    }

    const updateHash = () => setActiveHash(window.location.hash || "");
    updateHash();

    if (window.location.hash === "") {
      window.scrollTo({ top: 0, behavior: "auto" });
      setActiveHash("");
    }

    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (!entry.isIntersecting) return;
          if (window.location.hash === "" && window.scrollY < 120) return;
          const id = `#${entry.target.id}`;
          setActiveHash(id);
          window.history.replaceState(null, "", id);
        });
      },
      { threshold: 0.45 }
    );

    // Observe hash sections
    const fragrances = document.querySelector("#fragrances");
    const about = document.querySelector("#about");
    const contact = document.querySelector("#contact");

    if (fragrances) observer.observe(fragrances);
    if (about) observer.observe(about);
    if (contact) observer.observe(contact);

    window.addEventListener("hashchange", updateHash);
    const onScroll = () => {
      if (window.scrollY < 50 && window.location.hash === "" && activeHash !== "") {
        setActiveHash("");
        window.history.replaceState(null, "", "/");
      }
    };
    window.addEventListener("scroll", onScroll, { passive: true });

    return () => {
      if (fragrances) observer.unobserve(fragrances);
      if (about) observer.unobserve(about);
      if (contact) observer.unobserve(contact);
      window.removeEventListener("hashchange", updateHash);
      window.removeEventListener("scroll", onScroll);
    };
  }, [loc.pathname, activeHash]);

  if (loc.pathname.startsWith("/admin")) return null;

  const waHref = buildWaUrl(whatsappNumber, generalMessage());
  const isActive = (path, hash = null) => {
    if (hash) return false;
    if (path === "/") {
      return loc.pathname === path && activeHash === "";
    }
    return loc.pathname === path;
  };

  const getHashHref = (hash) => (loc.pathname === "/" ? hash : `/${hash}`);
  const handleHashNav = (hash) => (event) => {
    if (loc.pathname === "/") {
      event.preventDefault();
      const target = document.querySelector(hash);
      if (target) {
        target.scrollIntoView({ behavior: "smooth", block: "start" });
        window.history.replaceState(null, "", hash);
      }
    }
  };
  const handleHomeClick = () => {
    if (loc.pathname === "/") {
      setActiveHash("");
      window.history.replaceState(null, "", "/");
      window.scrollTo({ top: 0, behavior: "smooth" });
    }
  };

  const NavLink = ({ to, hash, children, testId, onClick }) => {
    const active = hash ? loc.pathname === "/" && activeHash === hash : isActive(to);
    const href = hash ? getHashHref(hash) : to;
    const Component = hash ? "a" : Link;
    const props = hash ? { href } : { to };
    const setRef = useCallback(
      (node) => {
        if (node) navRefs.current[testId] = node;
      },
      [testId]
    );

    return (
      <Component
        {...props}
        onClick={onClick}
        data-testid={testId}
        ref={setRef}
        className={`text-[11px] tracking-[0.22em] uppercase transition-colors relative pb-1 ${
          active ? "text-[#3B2618]" : "text-[#3B2618]/85 hover:text-[#8B5E3C]"
        }`}
      >
        {children}
      </Component>
    );
  };

  return (
    <header
      data-testid="site-header"
      className="sticky top-0 z-40 bg-[#F9F6F0]/95 backdrop-blur-xl border-b border-[#8B5E3C]/10"
    >
      <div className="px-6 md:px-10 lg:px-14 py-2 flex items-center justify-between gap-6">
        <Link to="/" data-testid="logo-link" className="shrink-0 flex items-center gap-2">
          <img src="/static/img/logotipo.jpg" alt="Escential" className="h-20 w-16 object-contain" style={{imageRendering: 'crisp-edges'}} />
          <div>
            <div className="font-serif-display text-xl md:text-2xl tracking-[0.12em] text-[#3B2618] font-medium">
              ESCENTIAL
            </div>
            <div className="font-serif-display text-xl md:text-2xl tracking-[0.12em] text-[#8B5E3C] font-medium">
              Collection
            </div>
          </div>
        </Link>

        <nav ref={navRef} className="hidden md:flex items-center gap-9 lg:gap-12 relative">
          <NavLink to="/" testId="nav-home" onClick={handleHomeClick}>{t("nav.home")}</NavLink>
          <NavLink to="/shop" testId="nav-shop">{t("nav.shop")}</NavLink>
          <NavLink hash="#about" testId="nav-about" onClick={handleHashNav("#about")}>{t("nav.about")}</NavLink>
          <NavLink hash="#fragrances" testId="nav-fragrances" onClick={handleHashNav("#fragrances")}>{t("nav.fragrances")}</NavLink>
          <NavLink hash="#contact" testId="nav-contact" onClick={handleHashNav("#contact")}>{t("nav.contact")}</NavLink>
          <span
            style={{
              left: indicatorStyle.left,
              width: indicatorStyle.width,
              opacity: indicatorStyle.opacity,
            }}
            className="absolute bottom-0 h-[1px] bg-[#8B5E3C] transition-all duration-300 ease-out"
          />
        </nav>

        <div className="flex items-center gap-3 sm:gap-5">
          <button
            data-testid="header-search-btn"
            className="hidden sm:block p-2 text-[#3B2618] hover:text-[#8B5E3C] transition-colors"
            aria-label="search"
            onClick={() => {}}
          >
            <Search className="w-5 h-5" strokeWidth={1.5} />
          </button>

          <button
            data-testid="mobile-menu-btn"
            onClick={() => setMenuOpen((v) => !v)}
            className="md:hidden p-2"
            aria-label="menu"
          >
            {menuOpen ? <X strokeWidth={1.5} className="w-6 h-6" /> : <Menu strokeWidth={1.5} className="w-6 h-6" />}
          </button>
        </div>
      </div>

      {menuOpen && (
        <div className="md:hidden border-t border-[#8B5E3C]/10 px-6 py-6 space-y-4 bg-[#F9F6F0]">
          <Link to="/" onClick={() => { setMenuOpen(false); if (loc.pathname === "/") window.scrollTo({ top: 0, behavior: "smooth" }); }} className="block text-xs tracking-[0.22em] uppercase">
            {t("nav.home")}
          </Link>
          <Link to="/shop" onClick={() => setMenuOpen(false)} className="block text-xs tracking-[0.22em] uppercase">
            {t("nav.shop")}
          </Link>
          <a
            href={getHashHref("#fragrances")}
            onClick={(event) => {
              setMenuOpen(false);
              if (loc.pathname === "/") {
                event.preventDefault();
                const target = document.querySelector("#fragrances");
                if (target) target.scrollIntoView({ behavior: "smooth", block: "start" });
                window.history.replaceState(null, "", "#fragrances");
              }
            }}
            className="block text-xs tracking-[0.22em] uppercase"
          >
            {t("nav.fragrances")}
          </a>
          <a
            href={getHashHref("#about")}
            onClick={(event) => {
              setMenuOpen(false);
              if (loc.pathname === "/") {
                event.preventDefault();
                const target = document.querySelector("#about");
                if (target) target.scrollIntoView({ behavior: "smooth", block: "start" });
                window.history.replaceState(null, "", "#about");
              }
            }}
            className="block text-xs tracking-[0.22em] uppercase"
          >
            {t("nav.about")}
          </a>
          <a
            href={getHashHref("#contact")}
            onClick={(event) => {
              setMenuOpen(false);
              if (loc.pathname === "/") {
                event.preventDefault();
                const target = document.querySelector("#contact");
                if (target) target.scrollIntoView({ behavior: "smooth", block: "start" });
                window.history.replaceState(null, "", "#contact");
              }
            }}
            className="block text-xs tracking-[0.22em] uppercase"
          >
            {t("nav.contact")}
          </a>
        </div>
      )}
    </header>
  );
};

export default Header;
