import React, { useEffect, useState } from "react";
import { useApp } from "../contexts/AppContext";
import ProductCard from "../components/ProductCard";

const Shop = () => {
  const { t } = useApp();
  const [products, setProducts] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const loadProducts = async () => {
      setIsLoading(true);
      setError(null);

      try {
        const response = await fetch("http://localhost:5000/api/products");
        if (!response.ok) throw new Error("Failed to load products");
        const data = await response.json();
        // Ordenar por field 'order' se existir
        const sorted = data.sort((a, b) => (a.order ?? 0) - (b.order ?? 0));
        setProducts(sorted || []);
      } catch (loadError) {
        console.error("Error loading products:", loadError);
        setError(loadError.message || "Unable to load products.");
        setProducts([]);
      } finally {
        setIsLoading(false);
      }
    };

    loadProducts();
  }, []);

  return (
    <main data-testid="shop-page" className="px-6 md:px-12 lg:px-20 pt-16 pb-20 lg:pt-24">
      <div className="mb-14">
        <span className="text-xs tracking-luxe uppercase text-[#8B5E3C]">Collection</span>
        <h1 className="font-serif-display text-5xl sm:text-6xl mt-3">{t("nav.shop")}</h1>
      </div>

      {isLoading ? (
        <div className="text-center py-16 text-[#8B5E3C]">Loading products...</div>
      ) : error ? (
        <div className="text-center py-16 text-[#964545]">{error}</div>
      ) : products.length === 0 ? (
        <div className="text-center py-16 text-[#8B5E3C]">No products available right now.</div>
      ) : (
        <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-6 lg:gap-10">
          {products.map((p, i) => (
            <ProductCard key={p.id} product={p} index={i} />
          ))}
        </div>
      )}
    </main>
  );
};

export default Shop;
