import React from "react";
import { Link } from "react-router-dom";
import { useApp } from "../contexts/AppContext";
import { Instagram, Mail } from "lucide-react";
import WhatsAppIcon from "../components/WhatsAppIcon";
import { buildWaUrl, generalMessage } from "../lib/whatsapp";

const HERO_IMG = "https://static.prod-images.emergentagent.com/jobs/2d82cc90-8f91-4611-9b61-a4e41c856c81/images/b6a16874e608d44fa4f9e08f82b3bf3d3a1f8c905e8033a4d387dd18b37945f3.png";
const STORY_IMG = "https://images.pexels.com/photos/12486412/pexels-photo-12486412.jpeg?auto=compress&cs=tinysrgb&dpr=2&h=900&w=900";
const PREMIUM_IMG = "https://media.istockphoto.com/id/1954159353/pt/foto/girl-lights-a-candle-aesthetic-cozy-photo.jpg?s=612x612&w=0&k=20&c=ks7N9B1AgOwbqUcFQrMsKryYorSFF5EjH-Vlaf8Ilqc=";
const FEELING_IMG = "https://static.prod-images.emergentagent.com/jobs/2d82cc90-8f91-4611-9b61-a4e41c856c81/images/c6d06910e66ee940450c722df7ee0ffccdbf939b162751a0c7b2f5d6348156f9.png";

const Stars = () => (
  <div className="text-[#8B5E3C] tracking-[0.3em]" aria-hidden>★★★★★</div>
);

const Home = () => {
  const { t, whatsappNumber } = useApp();

  const fragranceCats = t("fragrances.categories");
  const reviewList = t("reviews.list");
  const premiumItems = t("premium.items");
  const waHref = buildWaUrl(whatsappNumber, generalMessage());

  return (
    <main data-testid="home-page">
      {/* HERO */}
      <section className="relative w-full h-[68vh] min-h-[480px] max-h-[700px] overflow-hidden">
        <img src={HERO_IMG} alt="Escential" className="absolute inset-0 w-full h-full object-cover" />
        <div className="absolute inset-0 bg-gradient-to-r from-[#3B2618]/45 via-[#3B2618]/15 to-transparent" />
        <div className="relative h-full flex items-center px-6 md:px-12 lg:px-20">
          <div className="max-w-xl fade-up">
            <h1 className="font-serif-display text-5xl sm:text-6xl lg:text-7xl text-[#F9F6F0] tracking-[0.08em]">
              {t("hero.title")}
            </h1>
            <p className="mt-5 text-sm sm:text-base tracking-[0.22em] uppercase text-[#F9F6F0]/90">
              {t("hero.subtitle")}
            </p>
            <Link
              data-testid="hero-cta"
              to="/shop"
              className="inline-block mt-9 bg-[#8B5E3C] text-[#F9F6F0] hover:bg-[#5C3A21] transition-colors px-9 py-4 text-[11px] tracking-[0.22em] uppercase"
            >
              {t("hero.cta")}
            </Link>
          </div>
        </div>
      </section>

      {/* OUR STORY */}
      <section id="about" className="px-6 md:px-12 lg:px-20 py-20 lg:py-28 bg-[#F9F6F0]">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10 lg:gap-16 items-center">
          <div className="lg:col-span-5">
            <div className="product-img-wrap aspect-[4/3] bg-[#EDE4D8] max-w-[460px]">
              <img src={STORY_IMG} alt="Our story" className="w-full h-full object-cover" />
            </div>
          </div>
          <div className="lg:col-span-7 text-center lg:pl-10">
            <div className="text-[10px] tracking-[0.3em] uppercase text-[#8B5E3C] mb-4">
              {t("story.eyebrow")}
            </div>
            <h2 className="font-serif-display text-3xl sm:text-4xl lg:text-5xl text-[#3B2618]">
              {t("story.title")}
            </h2>
            <div className="w-10 h-px bg-[#8B5E3C]/40 mx-auto my-6" />
            <p className="text-[#3B2618]/75 leading-relaxed max-w-lg mx-auto">
              {t("story.text")}
            </p>
            <a
              href="#fragrances"
              className="inline-block mt-8 border border-[#8B5E3C] text-[#8B5E3C] hover:bg-[#8B5E3C] hover:text-[#F9F6F0] transition-colors px-8 py-3.5 text-[11px] tracking-[0.22em] uppercase"
            >
              {t("story.cta")}
            </a>
          </div>
        </div>
      </section>

      {/* PREMIUM BOX */}
      <section className="bg-[#EDE4D8]">
        <div className="grid grid-cols-1 lg:grid-cols-2">
          <div className="px-6 md:px-12 lg:px-20 py-20 lg:py-28 flex flex-col justify-center">
            <div className="text-sm tracking-[0.3em] uppercase text-[#8B5E3C] mb-2">{t("premium.eyebrow")}</div>
            <h2 className="font-serif-display text-4xl sm:text-5xl lg:text-6xl text-[#3B2618] tracking-[0.06em]">
              {t("premium.title")}
            </h2>
            <ul className="mt-10 space-y-3.5 text-[12px] tracking-[0.25em] uppercase text-[#3B2618]/85">
              {premiumItems.map((item, i) => (
                <li key={i} className="flex items-start gap-3">
                  <span className="text-[#8B5E3C]">•</span>
                  <span>{item}</span>
                </li>
              ))}
            </ul>
            <Link
              to="/shop"
              className="inline-block mt-10 w-fit bg-[#8B5E3C] text-[#F9F6F0] hover:bg-[#5C3A21] transition-colors px-8 py-3.5 text-[11px] tracking-[0.22em] uppercase"
            >
              {t("premium.cta")}
            </Link>
          </div>
          <div className="relative min-h-[360px] lg:min-h-[560px]">
            <img src={PREMIUM_IMG} alt="Premium Box" className="absolute inset-0 w-full h-full object-cover" />
          </div>
        </div>
      </section>

      {/* OUR FRAGRANCES */}
      <section id="fragrances" className="px-6 md:px-12 lg:px-20 py-20 lg:py-28">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-12 mb-14">
          <div className="lg:col-span-5">
            <div className="text-[10px] tracking-[0.3em] uppercase text-[#8B5E3C] mb-3">{t("fragrances.eyebrow")}</div>
            <h2 className="font-serif-display text-3xl sm:text-4xl lg:text-5xl text-[#3B2618] leading-[1.1]">
              {t("fragrances.title")}
            </h2>
          </div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-3 gap-8 lg:gap-12">
          {fragranceCats.map((cat, i) => (
            <div key={i} className="fade-up group" style={{ animationDelay: `${i * 0.1}s` }}>
              <div className="product-img-wrap aspect-[5/4] bg-[#EDE4D8] mb-5">
                <img src={cat.image} alt={cat.name} className="w-full h-full object-cover" loading="lazy" />
              </div>
              <h3 className="text-xs tracking-[0.25em] uppercase text-[#3B2618] mb-2">{cat.name}</h3>
              <p className="text-sm text-[#3B2618]/75 leading-relaxed mb-3">{cat.desc}</p>
              <p className="text-xs text-[#A68A72] mb-4">
                <span className="font-semibold text-[#3B2618]">{t("fragrances.notes")}:</span>{" "}{cat.notes}
              </p>
              <Link to="/shop" className="text-[11px] tracking-[0.25em] uppercase text-[#8B5E3C] hover:text-[#5C3A21] border-b border-[#8B5E3C] pb-0.5">
                {t("fragrances.shop_now")}
              </Link>
            </div>
          ))}
        </div>
      </section>

      {/* MORE THAN FRAGRANCE — full-width dark hero */}
      <section className="relative w-full h-[55vh] min-h-[380px] max-h-[560px] overflow-hidden">
        <img src={FEELING_IMG} alt="A feeling" className="absolute inset-0 w-full h-full object-cover" />
        <div className="absolute inset-0 bg-gradient-to-r from-[#3B2618]/65 via-[#3B2618]/30 to-transparent" />
        <div className="relative h-full flex items-center px-6 md:px-12 lg:px-20">
          <div className="max-w-xl">
            <div className="text-xs sm:text-sm tracking-[0.3em] uppercase text-[#F9F6F0]">{t("feeling.title_top")}</div>
            <h2 className="font-serif-display text-4xl sm:text-5xl lg:text-6xl text-[#F9F6F0] mt-3">
              {t("feeling.title_bottom")}
            </h2>
            <a
              href={waHref}
              target="_blank"
              rel="noopener noreferrer"
              className="inline-flex items-center gap-3 mt-8 bg-[#F9F6F0] text-[#3B2618] hover:bg-[#8B5E3C] hover:text-[#F9F6F0] transition-colors px-8 py-3.5 text-[11px] tracking-[0.22em] uppercase"
            >
              {t("feeling.cta")}
            </a>
          </div>
        </div>
      </section>

      {/* REVIEWS */}
      <section className="px-6 md:px-12 lg:px-20 py-20 lg:py-24">
        <h3 className="text-center text-xs tracking-[0.3em] uppercase text-[#3B2618] mb-12">
          {t("reviews.title")}
        </h3>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-12 max-w-5xl mx-auto">
          {reviewList.map((r, i) => (
            <div key={i} className="text-center">
              <div className="flex justify-center mb-4"><Stars /></div>
              <p className="text-[#3B2618]/85 italic leading-relaxed mb-4">"{r.quote}"</p>
              <p className="text-xs tracking-[0.25em] uppercase text-[#A68A72]">— {r.author}</p>
            </div>
          ))}
        </div>
      </section>
    </main>
  );
};

export default Home;
