import React, { useState } from "react";
import { useLocation, Link } from "react-router-dom";
import { Instagram, Mail, ArrowRight } from "lucide-react";
import { useApp } from "../contexts/AppContext";
import WhatsAppIcon from "./WhatsAppIcon";
import { buildWaUrl, generalMessage } from "../lib/whatsapp";

const Footer = () => {
  const { t, whatsappNumber } = useApp();
  const loc = useLocation();
  const [email, setEmail] = useState("");
  const [subscribed, setSubscribed] = useState(false);

  if (loc.pathname.startsWith("/admin")) return null;

  const waHref = buildWaUrl(whatsappNumber, generalMessage());
  const shopLinks = t("footer.shop_links");
  const infoLinks = t("footer.info_links");

  const onSubmit = (e) => {
    e.preventDefault();
    if (email) setSubscribed(true);
  };

  return (
    <footer id="contact" data-testid="site-footer" className="border-t border-[#8B5E3C]/10 bg-[#F9F6F0]">
      <div className="px-6 md:px-12 lg:px-20 py-16 lg:py-20 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-12 gap-12">
        {/* Brand */}
        <div className="lg:col-span-3">
          <div className="font-serif-display text-2xl tracking-[0.18em] text-[#3B2618]">ESCENTIAL</div>
          <p className="mt-4 text-sm text-[#3B2618]/70 italic max-w-xs">
            {t("footer.tagline")}
          </p>
          <div className="flex items-center gap-3 mt-6">
            <a
              href="https://www.instagram.com/escential.collection/"
              target="_blank"
              rel="noopener noreferrer"
              aria-label="Instagram"
              className="p-2 text-[#3B2618] hover:text-[#8B5E3C] border border-[#E0D3C3] hover:border-[#8B5E3C] transition-colors"
            >
              <Instagram className="w-4 h-4" strokeWidth={1.25} />
            </a>
            <a
              href={waHref}
              target="_blank"
              rel="noopener noreferrer"
              aria-label="WhatsApp"
              className="p-2 text-[#3B2618] hover:text-[#25D366] border border-[#E0D3C3] hover:border-[#25D366] transition-colors"
            >
              <WhatsAppIcon className="w-4 h-4" strokeWidth={1.25} />
            </a>
            <a
              href="mailto:hello@escentialfragrance.com"
              aria-label="Email"
              className="p-2 text-[#3B2618] hover:text-[#8B5E3C] border border-[#E0D3C3] hover:border-[#8B5E3C] transition-colors"
            >
              <Mail className="w-4 h-4" strokeWidth={1.25} />
            </a>
          </div>
        </div>

        {/* Shop */}
        <div className="lg:col-span-2">
          <div className="text-xs tracking-[0.25em] uppercase text-[#8B5E3C] mb-5">{t("footer.shop_title")}</div>
          <ul className="space-y-3 text-sm">
            {shopLinks.map((l, i) => (
              <li key={i}>
                <Link to="/shop" className="text-[#3B2618]/80 hover:text-[#8B5E3C]">{l}</Link>
              </li>
            ))}
          </ul>
        </div>

        {/* Information */}
        <div className="lg:col-span-3">
          <div className="text-xs tracking-[0.25em] uppercase text-[#8B5E3C] mb-5">{t("footer.info_title")}</div>
          <ul className="space-y-3 text-sm">
            {infoLinks.map((l, i) => (
              <li key={i}>
                <a href={i === 0 ? "/#about" : i === infoLinks.length - 1 ? waHref : "/#fragrances"} target={i === infoLinks.length - 1 ? "_blank" : undefined} rel={i === infoLinks.length - 1 ? "noopener noreferrer" : undefined} className="text-[#3B2618]/80 hover:text-[#8B5E3C]">
                  {l}
                </a>
              </li>
            ))}
          </ul>
        </div>

        {/* Newsletter */}
        <div className="lg:col-span-4">
          <div className="text-xs tracking-[0.25em] uppercase text-[#8B5E3C] mb-3">{t("footer.newsletter_title")}</div>
          <p className="text-sm text-[#3B2618]/75 mb-5">{t("footer.newsletter_text")}</p>
          {subscribed ? (
            <p className="text-sm text-[#506B52]" data-testid="newsletter-success">✓ Subscribed. Thank you.</p>
          ) : (
            <form onSubmit={onSubmit} className="flex items-center border-b border-[#8B5E3C]/40">
              <input
                data-testid="newsletter-email"
                type="email"
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder={t("footer.newsletter_placeholder")}
                className="flex-1 bg-transparent py-3 outline-none text-sm placeholder:text-[#A68A72]"
              />
              <button
                data-testid="newsletter-submit"
                type="submit"
                className="p-2 text-[#8B5E3C] hover:text-[#5C3A21]"
              >
                <ArrowRight className="w-4 h-4" strokeWidth={1.5} />
              </button>
            </form>
          )}
        </div>
      </div>

      <div className="border-t border-[#8B5E3C]/10 px-6 md:px-12 lg:px-20 py-6 flex flex-wrap justify-between gap-3 text-[10px] tracking-[0.22em] uppercase text-[#A68A72]">
        <span>© {new Date().getFullYear()} Escential Fragrance</span>
        <span>{t("footer.rights")}</span>
      </div>
    </footer>
  );
};

export default Footer;
