import React from "react";
import { Link } from "react-router-dom";
import { useApp } from "../contexts/AppContext";
import WhatsAppIcon from "./WhatsAppIcon";
import { buildWaUrl, productMessage } from "../lib/whatsapp";

const ProductCard = ({ product, index = 0 }) => {
  const { formatPrice, whatsappNumber } = useApp();
  const name = product.name_en;
  const img = product.images?.[0] || "https://images.unsplash.com/photo-1627808587525-194446b07384?w=800";
  const waHref = buildWaUrl(whatsappNumber, productMessage(product));

  return (
    <div
      data-testid={`product-card-${product.id}`}
      className={`fade-up fade-up-delay-${Math.min(index, 4)} group`}
    >
      <Link to={`/product/${product.id}`} className="block">
        <div className="product-img-wrap bg-[#EDE4D8] aspect-[3/4] mb-5">
          <img
            src={img}
            alt={name}
            className="w-full h-full object-cover"
            loading="lazy"
          />
        </div>
      </Link>
      <div>
        <Link to={`/product/${product.id}`} className="block">
          <h3 className="font-serif-display text-base sm:text-lg text-[#3B2618] hover:text-[#8B5E3C] transition-colors">
            {name}
          </h3>
        </Link>
        <div className="flex items-center justify-between mt-1 gap-2 min-h-[20px]">
          <p className="text-sm text-[#A68A72]">
            {formatPrice(undefined, product.price_gbp)}
          </p>
          <a
            data-testid={`whatsapp-${product.id}`}
            href={waHref}
            target="_blank"
            rel="noopener noreferrer"
            onClick={(e) => e.stopPropagation()}
            className="inline-flex items-center gap-1.5 text-[10px] tracking-luxe uppercase text-[#8B5E3C] hover:text-[#25D366] opacity-0 group-hover:opacity-100 transition-opacity duration-300"
          >
            <WhatsAppIcon className="w-4 h-4" strokeWidth={1.5} />
            WhatsApp
          </a>
        </div>
      </div>
    </div>
  );
};

export default ProductCard;
